texttool_globals_toast___read_text_completely = TextObject(bs_BA="Za nastavak u cjelosti pročitajte tekst.", cs_CZ="Abyste mohli pokračovat, přečtěte si prosím celý text.", da_DK="Læs tekst fuldstændigt for at fortsætte.", de_DE="Bitte lies den Text vollständig, um fortzufahren.", el_GR="Διαβάστε ολόκληρο το κείμενο, για να συνεχίσετε.", en_GB="Please read the text in full to continue.", es_ES="Por favor, lea el texto completo para seguir.", fi_FI="Lue teksti kokonaan jatkaaksesi.", fr_FR="Veuillez lire entièrement le texte pour poursuivre.", hr_HR="Pročitajte tekst do kraja kako biste nastavili.", hu_HU="Kérünk, olvasd el teljesen a szöveget a folytatáshoz.", it_IT="Per continuare, leggere il testo per intero.", nl_NL="Lees de tekst volledig om verder te gaan.", no_NO="Les hele teksten for å fortsette.", pl_PL="Aby kontynuować. proszę przeczytać tekst w całości.", pt_PT="Por favor, lê o texto na integra para poderes prosseguir.", ro_RO="Citiţi integral textul, pentru a continua.", ru_RU="Пожалуйста, прочитайте текст полностью, чтобы продолжить.", sk_SK="Prosím, na pokračovanie si prečítajte celý text.", sl_SI="Za nadaljevanje besedilo preberite do konca.", sr_RS="Pročitajte tekst u potpunosti da biste nastavili.", sv_SE="Läs texten helt för att fortsätta.", tr_TR="Devam etmek için lütfen metni tamamen oku.", uk_UA="Будь ласка, прочитайте текст повністю, щоб продовжити.")
